    def run_multi_turn_analysis(self, initial_task: str, follow_ups: list[str]) -> list[str]:
        """Execute multi-turn agentic workflow with conversation persistence."""
        tools = self._define_advanced_tools()
        results = []

        # Initial task
        all_tasks = [initial_task] + follow_ups

        for turn, task in enumerate(all_tasks):
            # Add user message
            self.conversation_history.append({"role": "user", "content": task})

            # Request agent response with tools
            response = self.client.messages.create(
                model=self.model,
                max_tokens=1024,
                tools=tools,
                messages=self.conversation_history
            )

            # Process response and tool calls
            assistant_content = []
            for block in response.content:
                if block.type == "tool_use":
                    tool_name = block.name
                    tool_input = block.input
                    tool_result = self._simulate_advanced_tool_execution(tool_name, tool_input)

                    assistant_content.append(block)

                    # Log execution
                    self.execution_trace.append({
                        "turn": turn,
                        "tool": tool_name,
                        "input": tool_input,
                        "result_keys": list(tool_result.keys())
                    })

                    # Add tool result to history for context
                    self.conversation_history.append({
                        "role": "assistant",
                        "content": assistant_content
                    })
                    self.conversation_history.append({
                        "role": "user",
                        "content": [{
                            "type": "tool_result",
                            "tool_use_id": block.id,
                            "content": json.dumps(tool_result)
                        }]
                    })

                elif hasattr(block, "text"):
                    results.append(block.text)
                    assistant_content.append(block)

            # Add final assistant response to history
            if assistant_content and not any(b.type == "tool_use" for b in assistant_content):
                self.conversation_history.append({"role": "assistant", "content": assistant_content})

        return results


